// <ContentViewContainer ref={...} onClick={e => {}} >
export const App = () => (
  <>
    <ContentViewContainer onClick={() => {}} />
    <StyledWrapper variant="primary">Content</StyledWrapper>
    <StaticAsWrapper variant="secondary">Static as content</StaticAsWrapper>
  </>
);
